                              </div>
                            </div>
                          ); 
                        })}
                    </div>
                
                  </>
                )}

                {activeTab==="history" && (


                

  <div className="space-y-4">

    <div className="flex items-center justify-between">
      <h3 className="text-xl font-bold">
        Previous Valuations
      </h3>

      <div className="text-sm text-zinc-400">
