                </div>

              </td>

              <td className="p-4">
                £{record["Market Retail"]}
              </td>

              <td className="p-4 text-[#00E51D]">
                £{record["Available Margin"]}
              </td>

              <td className="p-4">
                {record["Opportunity Score"]}
              </td>

            </tr>

          ))}

        </tbody>

      </table>

    </div>

  </div>
)}
              </div>
            </div>
          </section>
        </div>
      </div>
    </main>
  );
