type Data={invoice:InvoiceRow;items:InvoiceItem[];payments:InvoicePayment[]};const money=(n:number)=>new Intl.NumberFormat("en-GB",{style:"currency",currency:"GBP"}).format(n);
export function InvoiceWorkflowStep({saleId,invoiceId,busy,back,completePayment}:{saleId:string;invoiceId:string;busy:boolean;back:()=>void;completePayment:(form:Record<string,unknown>)=>Promise<void>}){const [data,setData]=useState<Data|null>(null),[loading,setLoading]=useState(true),[saving,setSaving]=useState(false),[error,setError]=useState("");async function load(){const r=await fetch(invoiceId?`/api/crm/invoices/${invoiceId}`:`/api/crm/invoices?sale_id=${saleId}`,{cache:"no-store"}),body=await r.json();if(!r.ok)throw new Error(body.error);setData(body);setLoading(false)}useEffect(()=>{void load().catch(e=>{setError(e instanceof Error?e.message:"Unable to load invoice.");setLoading(false)})},[saleId,invoiceId]);async function add(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!data)return;const form=e.currentTarget,f=new FormData(form),description=String(f.get("description")||""),quantity=Number(f.get("quantity")||1),unit=Number(f.get("unit_price")||0),line=quantity*unit,temp:InvoiceItem={id:`temp-${Date.now()}`,description,quantity,unit_price:unit,line_total:line,item_type:"other",sort_order:100};setData({...data,items:[...data.items,temp],invoice:{...data.invoice,subtotal:data.invoice.subtotal+line,total:data.invoice.total+line,balance:data.invoice.balance+line}});setSaving(true);setError("");const r=await fetch(`/api/crm/invoices/${data.invoice.id}/items`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({description,quantity,unit_price:unit})});if(!r.ok)setError((await r.json()).error||"Unable to add item.");else{form.reset();await load()}setSaving(false)}async function payment(e:React.FormEvent<HTMLFormElement>){e.preventDefault();await completePayment(Object.fromEntries(new FormData(e.currentTarget)))}return <div className="workflow-invoice"><h2>Invoice and payment</h2><p>Add delivery or other products, review the live invoice, then record the balance payment.</p>{loading&&<div className="invoice-loading">Loading invoice...</div>}{error&&<p className="invoice-error">{error}</p>}{data&&<><div className="workflow-invoice-actions"><Link target="_blank" href={`/admin/accounts/invoices/${data.invoice.id}/document`}>View invoice</Link><Link target="_blank" href={`/admin/accounts/invoices/${data.invoice.id}/document`}>Print invoice</Link><a href={`/api/crm/invoices/${data.invoice.id}/pdf`}>Download PDF</a></div><section className="workflow-invoice-preview"><header><b>{data.invoice.invoice_number}</b><span className={`invoice-status ${data.invoice.status}`}>{data.invoice.status}</span></header>{data.items.map(item=><div key={item.id}><span>{item.description}<small>{item.quantity} × {money(item.unit_price)}</small></span><b>{money(item.line_total)}</b></div>)}<footer><span>Paid <b>{money(data.invoice.paid)}</b></span><strong>Balance due {money(data.invoice.balance)}</strong></footer></section><form className="workflow-add-item" onSubmit={add}><input name="description" placeholder="Product/item, e.g. Nationwide delivery" required/><input name="quantity" type="number" min="0.01" step="0.01" defaultValue="1" required/><input name="unit_price" type="number" step="0.01" placeholder="Price" required/><button disabled={saving}>{saving?"Adding...":"Add product/item"}</button></form><form className="wizard-form-grid workflow-payment" onSubmit={payment}><label><span>Payment amount</span><input name="amount" type="number" min="0.01" step="0.01" defaultValue={String(data.invoice.balance)}/></label><label><span>Payment method</span><select name="method"><option>Card</option><option>Cash</option><option>Bank</option><option>Finance</option><option>Part Exchange</option><option>Mixed</option></select></label><label><span>Receipt number</span><input name="receipt_number"/></label><label className="full"><span>Payment notes</span><textarea name="notes" rows={3}/></label><div className="wizard-actions"><button type="button" onClick={back}>Back</button><button className="primary" disabled={busy}>{busy?"Saving...":"Save payment and continue"}</button></div></form></>}</div>}

