"use client";
import {FormEvent,useEffect,useMemo,useState} from "react";import {useRouter} from "next/navigation";import {AddressLookup,type AddressValue} from "@/components/common/AddressLookup";import {CustomerLocationMap} from "@/components/maps/CustomerLocationMap";import {InvoiceWorkflowStep} from "./invoice-workflow-step";
type Customer={id:string;first_name:string;last_name:string;email:string|null;phone:string|null;house_name_number:string|null;street:string|null;address_line_1:string|null;address_line_2:string|null;address_line_3:string|null;city:string|null;county:string|null;postcode:string|null;country:string|null;latitude:number|null;longitude:number|null};
type Bike={id:number;registration:string|null;vin:string|null;stock_number:string|null;make:string|null;model:string|null;variant:string|null;year:number|null;mileage:number|null;price:number|null;status:string;primary_image_url:string|null};
type Address={id:string;label:string;house:string;street:string;line1:string;line2:string;town:string;county:string;postcode:string;country:string;latitude:number|null;longitude:number|null};
const steps=["Customer","Lead","Motorcycle","Reserve & deposit","Finance & sale","Invoice & payment","Delivery","Complete"];
const blankAddress:AddressValue={buildingNumber:"",buildingName:"",addressLine1:"",addressLine2:"",addressLine3:"",town:"",county:"",postcode:"",country:"United Kingdom",latitude:null,longitude:null};
export function SalesWizard({customers,stock,defaultCustomer="",defaultBike=""}:{customers:Customer[];stock:Bike[];defaultCustomer?:string;defaultBike?:string}){const router=useRouter();const [step,setStep]=useState(0),[customerId,setCustomerId]=useState(defaultCustomer),[leadId,setLeadId]=useState(""),[bikeId,setBikeId]=useState(defaultBike),[reservationId,setReservationId]=useState(""),[saleId,setSaleId]=useState(""),[invoiceId,setInvoiceId]=useState(""),[finance,setFinance]=useState(false),[busy,setBusy]=useState(false),[error,setError]=useState(""),[postcode,setPostcode]=useState(""),[addresses,setAddresses]=useState<Address[]>([]),[addressBusy,setAddressBusy]=useState(false);const customer=customers.find(item=>item.id===customerId),bike=stock.find(item=>String(item.id)===bikeId);const call=async(payload:Record<string,unknown>)=>{setBusy(true);setError("");const response=await fetch("/api/crm/sales-workflow",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});const result=await response.json() as Record<string,unknown>;setBusy(false);if(!response.ok){setError(String(result.error||"Unable to continue."));throw new Error(String(result.error))}return result};const searchStock=useMemo(()=>stock,[stock]);
  async function lookupAddress(){if(!postcode.trim())return;setAddressBusy(true);setError("");const response=await fetch(`/api/postcode-lookup?postcode=${encodeURIComponent(postcode)}`);const result=await response.json() as {addresses?:Address[];error?:string};setAddressBusy(false);if(!response.ok){setError(result.error||"Postcode not found.");return}setAddresses(result.addresses??[])}
  async function chooseAddress(address:Address){if(!customerId)return;setBusy(true);const response=await fetch(`/api/crm/customers/${customerId}`,{method:"PATCH",headers:{"Content-Type":"application/json"},body:JSON.stringify({house_name_number:address.house,street:address.street,address_line_1:address.line1,address_line_2:address.line2,city:address.town,county:address.county,postcode:address.postcode,country:address.country,latitude:address.latitude,longitude:address.longitude})});setBusy(false);if(!response.ok){const result=await response.json() as {error?:string};setError(result.error||"Unable to save address.");return}setAddresses([]);router.refresh()}
  const [wizardAddress,setWizardAddress]=useState<AddressValue>(blankAddress);useEffect(()=>{setWizardAddress(customer?{buildingNumber:customer.house_name_number??"",buildingName:"",addressLine1:customer.address_line_1??"",addressLine2:customer.address_line_2??"",addressLine3:"",town:customer.city??"",county:customer.county??"",postcode:customer.postcode??"",country:customer.country??"United Kingdom",latitude:customer.latitude,longitude:customer.longitude}:blankAddress)},[customerId]);async function saveWizardAddress(next:AddressValue){setWizardAddress(next);if(!customerId)return;const response=await fetch(`/api/crm/customers/${customerId}`,{method:"PATCH",headers:{"Content-Type":"application/json"},body:JSON.stringify({house_name_number:[next.buildingNumber,next.buildingName].filter(Boolean).join(" "),address_line_1:next.addressLine1,address_line_2:next.addressLine2,address_line_3:next.addressLine3,city:next.town,county:next.county,postcode:next.postcode,country:next.country,latitude:next.latitude,longitude:next.longitude})});if(!response.ok){const result=await response.json() as {error?:string};setError(result.error||"Unable to save customer address.")}}
  return <div className="sales-wizard"><nav className="sales-progress">{steps.map((label,index)=><div className={index===step?"active":index<step?"done":""} key={label}><i>{index<step?"✓":index+1}</i><span>{label}</span></div>)}</nav>{error&&<p className="stock-save-message">{error}</p>}<section className="sales-step">{step===0&&customer&&<div className="wizard-shared-address"><AddressLookup value={wizardAddress} onChange={next=>void saveWizardAddress(next)}/>{wizardAddress.latitude!=null&&wizardAddress.longitude!=null&&<CustomerLocationMap latitude={wizardAddress.latitude} longitude={wizardAddress.longitude} address={[wizardAddress.addressLine1,wizardAddress.town,wizardAddress.postcode].filter(Boolean).join(", ")}/>}</div>}
