function dealerAdvertFallback(bike:SupabaseStockBike){const nested=bike.dealer5_data&&typeof bike.dealer5_data==="object"?(bike.dealer5_data as {fields?:unknown}).fields:null;const fields=nested&&typeof nested==="object"&&!Array.isArray(nested)?nested as Record<string,unknown>:{};const result:Record<string,string>={};const confirm=text(fields["Confirm Spec"])||text(bike.description);const headline=text(fields["Attention Grabber (30 Chars - Autotrader/Website)"])||text(fields["Attention Grabber"]);if(headline)result.advert_headline=headline;if(!confirm)return result;let prepared=confirm.replace(/\r/g,"");for(const [key,aliases] of advertHeadings)for(const alias of aliases){const escaped=alias.replace(/[.*+?^${}()|[\]\\]/g,"\\$&").replace(/\s+/g,"\\s+");prepared=prepared.replace(new RegExp(`${escaped}\\s*:?`,"gi"),`\n@@${key}@@\n`)}let current="intro_description";for(const raw of prepared.split(/\n+/)){const line=raw.trim();if(!line)continue;const marker=line.match(/^@@(.+)@@$/);if(marker){current=marker[1];continue}result[current]=result[current]?`${result[current]}\n${line}`:line}return result}

