  const shown=useMemo(()=>bikes.filter(bike=>{const status=normal(bike.status);const statusMatch=filter==="all"||(filter==="active"&&["in stock","on forecourt","reserved","prep"].includes(status))||(filter==="live"&&["in stock","on forecourt"].includes(status))||(filter==="reserved"&&status==="reserved")||(filter==="sold"&&["sold","sale completed"].includes(status))||(filter==="prep"&&status==="prep");const searchMatch=!query||`${bike.make??""} ${bike.model??""} ${bike.variant??""} ${bike.registration??""} ${bike.stock_number??""}`.toLowerCase().includes(query.toLowerCase());const images=[bike.primary_image_url,...bike.image_urls].filter(Boolean);const warningMatch=warning==="image"?images.length===0:warning==="price"?bike.price==null||bike.price<=0:true;return statusMatch&&searchMatch&&warningMatch}),[bikes,filter,query,warning]);

  return <>
